import{_ as s,o as e,c as n,a2 as i}from"./chunks/framework.OWFDNrRT.js";const u=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1773460793000}'),t={name:"guide/getting-started.md"};function l(o,a,p,r,d,c){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>This guide walks you through setting up DINOForge for development or mod authoring.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li><a href="https://dotnet.microsoft.com/download" target="_blank" rel="noreferrer">.NET 8 SDK</a> or later</li><li><a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js 20+</a> (for docs only)</li><li>Diplomacy is Not an Option (Steam)</li><li>Git</li></ul><h2 id="install-bepinex-and-dinoforge" tabindex="-1">Install BepInEx and DINOForge <a class="header-anchor" href="#install-bepinex-and-dinoforge" aria-label="Permalink to &quot;Install BepInEx and DINOForge&quot;">​</a></h2><p>DINOForge runs on a <strong>modified BepInEx 5</strong> build with Unity ECS support. Standard BepInEx from GitHub will not work.</p><h3 id="option-a-automated-installer-recommended-for-users" tabindex="-1">Option A: Automated Installer (Recommended for Users) <a class="header-anchor" href="#option-a-automated-installer-recommended-for-users" aria-label="Permalink to &quot;Option A: Automated Installer (Recommended for Users)&quot;">​</a></h3><p>DINOForge includes a GUI installer that handles BepInEx and DINOForge setup automatically.</p><ol><li>Download the latest DINOForge installer from <a href="https://github.com/KooshaPari/Dino/releases" target="_blank" rel="noreferrer">Releases</a></li><li>Run <code>DINOForge.Installer.exe</code></li><li>Select your DINO game installation directory</li><li>The installer will: <ul><li>Download and extract the modified BepInEx 5</li><li>Install DINOForge Runtime and example packs</li><li>Verify the installation</li></ul></li><li>Launch the game and verify mods load (F10 to open mod menu)</li></ol><h3 id="option-b-manual-installation-for-developers" tabindex="-1">Option B: Manual Installation (For Developers) <a class="header-anchor" href="#option-b-manual-installation-for-developers" aria-label="Permalink to &quot;Option B: Manual Installation (For Developers)&quot;">​</a></h3><p>If you prefer manual setup or the installer doesn&#39;t work for you:</p><ol><li>Download <strong>BepInEx 5 with Unity ECS Support</strong> from <a href="https://www.nexusmods.com/diplomacyisnotanoption/mods/1" target="_blank" rel="noreferrer">Nexus Mods</a></li><li>Extract into your DINO game directory (where the <code>.exe</code> lives)</li><li>Verify the folder structure:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GameRoot/</span></span>
<span class="line"><span>  winhttp.dll              # Modified Doorstop pre-loader</span></span>
<span class="line"><span>  doorstop_config.ini</span></span>
<span class="line"><span>  BepInEx/</span></span>
<span class="line"><span>    plugins/               # Standard plugins (empty for DINO)</span></span>
<span class="line"><span>    ecs_plugins/           # WHERE DINO MODS GO</span></span>
<span class="line"><span>    config/                # Configuration files</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Standard BepInEx does <strong>not</strong> work with DINO. The game uses full Unity ECS (DOTS) with Burst compilation, which requires a modified Doorstop pre-loader fork.</p></div><ol start="4"><li>Launch the game once to let BepInEx initialize, then close it.</li><li>Copy the built <code>DINOForge.Runtime.dll</code> to <code>BepInEx/ecs_plugins/</code></li></ol><h2 id="clone-and-build" tabindex="-1">Clone and Build <a class="header-anchor" href="#clone-and-build" aria-label="Permalink to &quot;Clone and Build&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/KooshaPari/Dino.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Dino</span></span></code></pre></div><p>Build the solution:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/DINOForge.sln</span></span></code></pre></div><p>Run tests to verify everything works:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/DINOForge.sln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbosity</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> normal</span></span></code></pre></div><h2 id="project-structure" tabindex="-1">Project Structure <a class="header-anchor" href="#project-structure" aria-label="Permalink to &quot;Project Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DINOForge/</span></span>
<span class="line"><span>  src/</span></span>
<span class="line"><span>    Runtime/           # BepInEx plugin — bootstrap, ECS detection, hooks</span></span>
<span class="line"><span>      Bridge/          #   ECS bridge: component mapping, stat modifiers</span></span>
<span class="line"><span>      HotReload/       #   Hot reload bridge</span></span>
<span class="line"><span>      UI/              #   Mod menu (F10), settings panel</span></span>
<span class="line"><span>    SDK/               # Public mod API — registries, schemas, pack loaders</span></span>
<span class="line"><span>      Assets/          #   Asset service, addressables catalog</span></span>
<span class="line"><span>      Dependencies/    #   Dependency resolver</span></span>
<span class="line"><span>      HotReload/       #   Pack file watcher</span></span>
<span class="line"><span>      Models/          #   Content data models</span></span>
<span class="line"><span>      Registry/        #   Generic registry with conflict detection</span></span>
<span class="line"><span>      Universe/        #   Universe Bible system</span></span>
<span class="line"><span>      Validation/      #   Schema validation (NJsonSchema)</span></span>
<span class="line"><span>    Bridge/</span></span>
<span class="line"><span>      Protocol/        #   JSON-RPC message types, IGameBridge</span></span>
<span class="line"><span>      Client/          #   Out-of-process game client</span></span>
<span class="line"><span>    Domains/</span></span>
<span class="line"><span>      Warfare/         #   Factions, doctrines, combat, waves</span></span>
<span class="line"><span>      Economy/         #   Rates, trade, balance</span></span>
<span class="line"><span>      Scenario/        #   Scripting, conditions</span></span>
<span class="line"><span>      UI/              #   HUD injection, menus</span></span>
<span class="line"><span>    Tools/</span></span>
<span class="line"><span>      Cli/             #   dinoforge CLI</span></span>
<span class="line"><span>      McpServer/       #   MCP server for Claude Code</span></span>
<span class="line"><span>      PackCompiler/    #   Pack compiler (validate, build)</span></span>
<span class="line"><span>      DumpTools/       #   Entity dump analysis (Spectre.Console)</span></span>
<span class="line"><span>      Installer/       #   BepInEx + DINOForge installer</span></span>
<span class="line"><span>    Tests/             # Unit tests (xUnit + FluentAssertions)</span></span>
<span class="line"><span>      Integration/     # Integration tests</span></span>
<span class="line"><span>  packs/               # Content packs (6 example packs)</span></span>
<span class="line"><span>  schemas/             # JSON/YAML schema definitions (17 schemas)</span></span>
<span class="line"><span>  docs/                # This documentation site</span></span></code></pre></div><h2 id="load-a-pack" tabindex="-1">Load a Pack <a class="header-anchor" href="#load-a-pack" aria-label="Permalink to &quot;Load a Pack&quot;">​</a></h2><p>Once built, the Runtime DLL goes into <code>BepInEx/ecs_plugins/</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BepInEx/ecs_plugins/DINOForge.Runtime.dll</span></span></code></pre></div><p>Content packs live in a <code>packs/</code> directory relative to the game root. The runtime discovers and loads them at boot.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/Dino/guide/quick-start">Quick Start</a> — Create your first pack in 5 minutes</li><li><a href="/Dino/guide/creating-packs">Creating Packs</a> — Full pack authoring guide</li><li><a href="/Dino/concepts/architecture">Architecture</a> — Understand the layered design</li></ul>`,29)])])}const g=s(t,[["render",l]]);export{u as __pageData,g as default};
